const resp = $input.first().json;
const stdout = resp.stdout || '';
const ok = resp.ok === true;
const duracion = resp.duracion_s ? `${Math.floor(resp.duracion_s/60)}m ${resp.duracion_s%60}s` : 'N/D';

const enviadosMatch = stdout.match(/Enviados OK\s*:\s*(\d+)/);
const erroresMatch  = stdout.match(/Errores\/Bounces\s*:\s*(\d+)/);

const enviados = enviadosMatch ? parseInt(enviadosMatch[1]) : 0;
const errores  = erroresMatch  ? parseInt(erroresMatch[1])  : 0;
const fecha = new Date().toLocaleString('es-ES', {timeZone: 'Europe/Madrid'});

let message;
if (!ok) {
  message = `❌ <b>Error en envío de emails</b>\n📅 ${fecha}\n\n<pre>${(resp.stderr || stdout).slice(-400)}</pre>`;
} else if (enviados === 0) {
  message = `ℹ️ <b>Envío completado</b>\n📅 ${fecha}\n\nNo había emails pendientes con dirección de contacto.`;
} else {
  const ico = errores > 0 ? '⚠️' : '✅';
  message = `${ico} <b>Envío de emails completado</b>\n📅 ${fecha}\n\n` +
            `✉️ Enviados: <b>${enviados}</b>\n` +
            `❌ Errores: ${errores}\n` +
            `⏱ Tiempo: ${duracion}\n\n` +
            `📋 Status updated in <code>generated_emails.json</code>`;
}
return [{ json: { message, ok, enviados, errores } }];
